var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"갑자기 왜 일어나나. 술잔은 아직 가득 차 있는데.","JPN":"急にどこに行くんだ。グラスにはまだ酒が残っているぞ。","ENG":"Getting up so soon? Your glass is still full.","TWN":"怎麼突然站起來了。酒杯還沒空呢。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......윌버. 당장 그 망할 놈을 찾으러 가야겠어.","JPN":"……ウィルバー。今すぐあのクソ野郎を見つけ出さないと。","ENG":"... Wilbur. I need to find that bastard right now.","TWN":"……韋爾伯。我要立刻去找那個該死的傢伙。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앉게.","JPN":"座ってくれ。","ENG":"Have a seat.","TWN":"坐下。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"술자리는 이제 끝났어. 네가 왔던 곳으로 돌아가기나 해.","JPN":"おしゃべりはもう終わりだ。お前は元の場所に戻れ。","ENG":"Party's over. Just go back to where you came from.","TWN":"不喝了，你從哪來回哪去吧。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이건 술친구로서 하는 충고야.","JPN":"これは飲み友達としての忠告だ。","ENG":"This is just a friendly tip from your drinking buddy.","TWN":"這是作為酒友的忠告。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앉게. 어서. 술자리는 아직 시작도 안 했어.","JPN":"座ってくれ。まだ話の途中だ。","ENG":"Have a seat. Now. We're only getting started.","TWN":"坐下。快，酒局還沒開始呢。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 매번 이 무렵에 마음대로 자리를 떠났지.","JPN":"君は毎回このタイミングで勝手に席を離れてしまう。","ENG":"You'd always get up around this point.","TWN":"你每次都是這個時候隨意離開。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이번만큼은 곤란해.","JPN":"だが今回だけは困る。","ENG":"But I can't have you doing that this time.","TWN":"但這次可不行。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"너...... 이제 보니 사람 깔보는 태도가 그 하얀 그림자와 비슷하군.","JPN":"お前……その人に対するナメた態度はあの白いシャドウに似ているな。","ENG":"Hang on... Come to think of it, you sound a lot like that pale Shadow, being all condescending.","TWN":"你……現在看來，你這傲慢的態度跟那個小白暗影很像啊。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......그러고 보니 더 수상해.","JPN":"……よく考えたら怪しいな。","ENG":"I just noticed this entire situation is super fishy...","TWN":"……如此說來，更奇怪了。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"왜 내가 여기서 끝도 없이 뭔가를 기다리고 있는 거지?","JPN":"なぜ私はここで何かをずっと待っているんだ？","ENG":"What am I waiting here for, exactly?","TWN":"為什麼我一直在這裡等待呢，我在等什麼？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"애초에 여긴 대체 어디야! 설마 너도 그년이랑 한통속이냐?!","JPN":"そもそもここはどこだ！　まさかお前もあの女とグルか！？","ENG":"Where the hell am I, even?! Are you working with that albino punk?!","TWN":"這裡到底是哪！難道你也跟她是一夥的？！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"두려워하는 심정은 나도 이해하네, 리타 아르세니코.","JPN":"恐れる気持ちは理解している、リタ・アルセニコ。","ENG":"I understand why you'd be afraid, Rita Arsenico.","TWN":"我理解你的恐懼，麗塔·阿塞妮克。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"두려워해? 내가?","JPN":"恐れるだと？　私が？","ENG":"Afraid? Me?","TWN":"恐懼？我嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 자네는 진실을 마주하기 두려워하고 있어.","JPN":"そう。君は真実と向き合うことを恐れている。","ENG":"That’s right. You're afraid to face the truth.","TWN":"是啊，你害怕面對真相。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"늘 그랬겠지. 진실을 마주하지 않아야 견딜 수 있었을 테니까.","JPN":"いつもそうして耐えてきたんだろう。真実から目を逸らすことで。","ENG":"Like you always have been. Avoiding the truth is the only way you can bear to go on living.","TWN":"你應該一直如此吧。因為只有不面對真相，你才能堅持下去。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 범죄자로 살아가기엔 너무 섬세한 사람이거든.","JPN":"君は犯罪者として生きるには、繊細すぎる人なんだよ。","ENG":"Your personality is far too delicate for the criminal life.","TWN":"你性格太過細膩，無法以罪人的身份活著。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};